mapper.select:
SELECT r.record_id, r.content_type, r.content_id, r.approval_status, r.audit_reason, r.insult_words, r.create_time FROM tb_content_audit_record r INNER JOIN ( SELECT content_id, MAX(create_time) AS max_time FROM tb_content_audit_record WHERE content_type = #{contentType}
AND content_id IN
#{contentId}
GROUP BY content_id ) latest ON r.content_id = latest.content_id AND r.create_time = latest.max_time WHERE r.content_type = #{contentType}

SELECT 
FROM tb_content_audit_record
WHERE 1=1
AND content_type = #{contentType}
AND approval_status = #{approvalStatus}

    AND audit_reason LIKE CONCAT('%', #{keyword}, '%')

ORDER BY create_time ${sortOrder}
